module multi_pipe_4bit
#(
    parameter size = 4
)
(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
    parameter size = 4;
    reg [3:0] reg_a, reg_b;
    reg [7:0] partial_product[0:size-1];
    reg [7:0] reg_sum[0:size-1];
    // Extend input signals
    wire [size-1:0] extend_a = {{size-4{1'b0}}, mul_a};
    wire [size-1:0] extend_b = {{size-4{1'b0}}, mul_b};
    // Generate partial products
    genvar i;
    generate
        for (i = 0; i < size; i = i + 1) begin : gen_partial_product
            if (i == 0) begin
                always @(*) begin
                    if (extend_b[i] == 1'b1)
                        partial_product[i] = extend_a << i;
                    else
                        partial_product[i] = 'd0;
                end
            end else begin
                always @(*) begin
                    if (extend_b[i] == 1'b1)
                        partial_product[i] = (extend_a << i);
                    else
                        partial_product[i] = 'd0;
                end
            end
        end
    endgenerate
    // Add partial products
    integer j;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (j = 0; j < size; j = j + 1) begin
                reg_sum[j] <= 'd0;
            end
        end else begin
            for (j = 0; j < size; j = j + 1) begin
                reg_sum[j] <= reg_sum[j] + partial_product[j];
            end
        end
    end
    // Calculate final product
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 'd0;
        end else begin
            mul_out <= reg_sum[0] + reg_sum[1] + reg_sum[2] + reg_sum[3];
        end
    end
endmodule
